### Edge Middleware for Request Interception and Authentication

Source: https://context7.com/vercel/vercel/llms.txt

Implements Edge Middleware to intercept requests, perform A/B testing based on geolocation, verify authentication tokens, and add security headers. Handles route matching with dynamic path rewriting and redirects unauthenticated users to login.

```javascript
// middleware.js - Edge Middleware
import { next, rewrite } from '@vercel/functions/middleware';
import { geolocation } from '@vercel/functions';

export async function middleware(request) {
  const url = new URL(request.url);
  const geo = geolocation(request);

  // A/B testing based on geography
  if (url.pathname.startsWith('/experiment')) {
    const variant = geo.country === 'US' ? 'a' : 'b';
    return rewrite(`/experiment/${variant}${url.pathname.slice(11)}`);
  }

  // Authentication check
  if (url.pathname.startsWith('/dashboard')) {
    const token = request.cookies.get('auth_token');

    if (!token) {
      return Response.redirect(new URL('/login', request.url));
    }

    // Verify token
    const isValid = await verifyAuthToken(token.value);
    if (!isValid) {
      return Response.redirect(new URL('/login', request.url));
    }
  }

  // Add custom headers
  const response = next();
  response.headers.set('X-Visitor-Country', geo.country);
  response.headers.set('X-Frame-Options', 'DENY');
  response.headers.set('X-Content-Type-Options', 'nosniff');

  return response;
}

export const config = {
  matcher: [
    '/experiment/:path*',
    '/dashboard/:path*',
    '/((?!api|_next/static|_next/image|favicon.ico).*)',
  ],
};

async function verifyAuthToken(token) {
  try {
    const response = await fetch('https://auth.example.com/verify', {
      headers: { Authorization: `Bearer ${token}` },
    });
    return response.ok;
  } catch {
    return false;
  }
}
```

